class Calculator {
    field Num $precision = 0.001;

    method add(Num $a, Num $b) -> Num {
        return $a + $b;
    }

    method get_precision() -> Num {
        return $precision;
    }

    method set_precision(Num $new_precision) -> Void {
        $precision = $new_precision;
    }
}
